        except Exception as e:
            error_msg = f"ParameterSpace JSON提取失败: {e}"
            if debug:
                print("=" * 80)
                print("🔴 DEBUG模式: ParameterSpace JSON提取失败，立刻终止")
                print("=" * 80)
                print(f"错误信息: {error_msg}")
                print(f"错误类型: {type(e).__name__}")
                import traceback
                print(f"\n完整堆栈跟踪:")
                print(f"{'─' * 80}")
                traceback.print_exc()
                print(f"{'─' * 80}")
                print(f"\n原始ParameterSpace标签内容:")
                print(space_str)
                print(f"{'─' * 80}")
                print("原始content")
                print(content)
                print("=" * 80)
                import sys
                sys.exit(1)
            else:
                print(error_msg)
            return None, error_msg
    def _extract_parameter_relation_code(self, content: str, debug: bool = False) -> Tuple[Optional[str], Optional[str]]:
        """
        提取ParameterRelationCode，返回(code, error_message)
        如果提取失败，error_message包含错误信息；如果成功，error_message为None
        """
