                    space_key = f"space_{idx}"
                    simulation_raw_data.setdefault(space_key, {
                        "parameter_space": parameter_space_dict,
                        "parameter_relation_code": parameter_relation_code,
                        "simulation_data": []
                    })

                    if interation_metrics and "simulation_raw_data" in interation_metrics:
                        sim = interation_metrics["simulation_raw_data"]
                        if isinstance(sim, list):
                            simulation_raw_data[space_key]["simulation_data"].extend(sim)
                        elif sim is not None:
                            simulation_raw_data[space_key]["simulation_data"].append(sim)

                    # 解析结果
                    try:
                        parsed = json.loads(interation_response_str)
                        if isinstance(parsed, list):
                            for item in parsed:
                                if isinstance(item, dict):
                                    item.pop("comment", None)
                                    item.setdefault("idx", idx)
                                    all_interation_results.append(item)
                                else:
                                    all_interation_results.append({"idx": idx, "result": str(item)})
                        elif isinstance(parsed, dict):
                            parsed.pop("comment", None)
                            parsed.setdefault("idx", idx)
                            all_interation_results.append(parsed)
                        else:
                            all_interation_results.append({"idx": idx, "result": interation_response_str})
                    except:
                        all_interation_results.append({"idx": idx, "result": interation_response_str})

                except Exception as e:
                    all_interation_results.append({"idx": idx, "result": f"Error calling {tool_name} for space idx {idx}: {str(e)}"})

            if not all_interation_results:
                all_interation_results = [{"idx": 0, "result": "No spaces to validate"}]

            check_valid_content = f"<CheckValid>{json.dumps(all_interation_results, ensure_ascii=False)}</CheckValid>"
            return False, check_valid_content, 0.0, {"simulation_raw_data": simulation_raw_data}

        except Exception as e:
            msg = f"Error calling {tool_name}: {str(e)}"
            check_valid_content = f"<CheckValid>[{{\"idx\": 0, \"result\": {json.dumps(msg, ensure_ascii=False)} }}]</CheckValid>"
            return False, check_valid_content, 0.0, {"simulation_raw_data": {}}
